class AppVersion {  final String latestVersion;  final int latestBuildNumber;  final String downloadUrl;  final bool mandatory;  final List<String> releaseNotes;  const AppVersion({    required this.latestVersion,    required this.latestBuildNumber,    required this.downloadUrl,    this.mandatory = false,    this.releaseNotes = const [],  });  factory AppVersion.fromJson(Map<String, dynamic> json) {    return AppVersion(      latestVersion: (json['latestVersion'] ?? '0.0.0').toString(),      latestBuildNumber: (json['latestBuildNumber'] ?? 0) as int,      downloadUrl: (json['downloadUrl'] ?? '').toString(),      mandatory: (json['mandatory'] ?? false) as bool,      releaseNotes: (json['releaseNotes'] as List<dynamic>?)              ?.map((e) => e.toString())              .toList() ??          [],    );  }

  bool isNewerThan(String currentVersion, int currentBuild) {    final latestParts = latestVersion.split('.').map(int.parse).toList();    final currentParts = currentVersion.split('.').map(int.parse).toList();    for (int i = 0; i < 3; i++) {      final l = i < latestParts.length ? latestParts[i] : 0;      final c = i < currentParts.length ? currentParts[i] : 0;      if (l != c) return l > c;    }
    return latestBuildNumber > currentBuild;  }}